/**
 *  支持过期时间的localStorage库
 */
declare const store: {
    preId: string;
    timeSign: string;
    status: {
        SUCCESS: number;
        FAILURE: number;
        OVERFLOW: number;
        TIMEOUT: number;
    };
    storage: Storage;
    getKey: (key: string) => string;
    set: (key: string, value: string | number, time?: number | Date | undefined, cb?: ((status: number, key: string, value: string | number) => void) | undefined) => void;
    get: (key: string, cb?: ((status: number, value: string | number | null) => void) | undefined) => {
        status: number;
        value: string | null;
    };
    remove: (key: string, cb?: ((status: number, value: string | number | null) => void) | undefined) => void;
};
export default store;
